// In ErrorHandler, before the AppError check:
if quotaErr, ok := err.(*QuotaError); ok {
	c.JSON(quotaErr.Code, quotaErr)
} else if appErr, ok := err.(*AppError); ok {
	c.JSON(appErr.Code, appErr)
}
```

